INSERT INTO terms
(id, lessonId, termName, definition, slangExplanation, example)
VALUES
(1, 1, 'Cc', 'An email field used to send a copy of a message to additional recipients.', 'Copy recipient field.', 'Put a teammate in Cc so they receive the same email.'),
(2, 1, 'Browser', 'A software application used to access and view webpages.', 'Web viewing app.', 'Chrome, Edge, and Firefox are browsers.'),
(3, 1, 'URL', 'The address used to locate a resource on the web.', 'Web address.', 'https://example.com is a URL.'),
(4, 1, 'Homepage', 'The main or starting page of a website or browser.', 'Starting page.', 'A website homepage often links to its main sections.'),
(5, 1, 'Hyperlink', 'A clickable text or object that opens another page, file, or location.', 'Clickable link.', 'Click a hyperlink to open another article.'),
(6, 1, 'Search Engine', 'An online service that helps users find information on the web.', 'Web search tool.', 'A search engine can find tutorials and documentation.'),
(7, 1, 'Download', 'To receive data from a remote system to a local device.', 'Get file from online.', 'Download a PDF lesson from the website.'),
(8, 1, 'Upload', 'To send data from a local device to a remote system.', 'Send file online.', 'Upload an avatar image to the server.'),
(9, 1, 'Domain Name', 'A human-readable name used to identify an Internet resource.', 'Readable website name.', 'example.com is a domain name.'),
(10, 1, 'Spam', 'Unwanted or unsolicited electronic messages, often sent in bulk.', 'Junk messages.', 'The filter moved the spam email to junk.'),
(11, 2, 'IMAP', 'Internet Message Access Protocol, used by mail clients to access email on a server.', 'Email access protocol.', 'A phone app may use IMAP to sync inbox messages.'),
(12, 2, 'SMTP', 'Simple Mail Transfer Protocol, used to send email messages.', 'Email sending protocol.', 'An app may use SMTP for outgoing mail.'),
(13, 2, 'DNS', 'A system that translates domain names into IP addresses.', 'Internet name lookup.', 'DNS resolves a domain to an IP address.'),
(14, 2, 'HTTP', 'A protocol used to transfer web data between clients and servers.', 'Basic web protocol.', 'A browser uses HTTP to request a webpage.'),
(15, 2, 'HTTPS', 'A secure version of HTTP that encrypts communication.', 'Secure web protocol.', 'Login pages should use HTTPS.'),
(16, 2, 'Cookie', 'A small piece of data stored by a website in a user browser.', 'Website browser data.', 'A cookie can remember a login session.'),
(17, 2, 'FTP', 'A protocol used to transfer files over a network.', 'File transfer protocol.', 'FTP can upload files to a server.'),
(18, 2, 'Web Server', 'A system that delivers web content to clients over the Internet.', 'Server that sends webpages.', 'An Express app can run as a web server.'),
(19, 2, 'Protocol', 'A set of rules for how systems communicate and exchange data.', 'Communication rule set.', 'HTTP and SMTP are protocols.'),
(20, 2, 'Bandwidth', 'The amount of data that can be transmitted over a network connection in a given time.', 'Network capacity.', 'Higher bandwidth can make downloads faster.'),
(21, 3, 'Ajax', 'Asynchronous JavaScript and XML, a technique for requesting data without reloading a whole webpage.', 'Background web request technique.', 'A quiz page can load answers using Ajax-style requests.'),
(22, 3, 'CDN', 'A content delivery network that serves content from distributed servers.', 'Distributed content servers.', 'A CDN can serve images from a nearby location.'),
(23, 3, 'CORS', 'A browser security mechanism that controls cross-origin requests.', 'Cross-site request rule.', 'CORS decides whether a frontend can call another origin.'),
(24, 3, 'DNSSEC', 'Security extensions that help verify DNS data authenticity.', 'Signed DNS.', 'DNSSEC can reduce the risk of forged DNS responses.'),
(25, 3, 'BGP', 'A routing protocol used to exchange routes between large networks on the Internet.', 'Internet backbone routing protocol.', 'ISPs use BGP to announce routes.'),
(26, 3, 'DKIM', 'An email authentication method that uses digital signatures.', 'Signed email verification.', 'DKIM helps verify that an email was not forged.'),
(27, 3, 'REST', 'An API design style based on resources and standard operations.', 'Resource-based API style.', 'A backend can expose REST endpoints for lessons.'),
(28, 3, 'SOAP', 'A protocol for exchanging structured web service messages, often with XML.', 'XML web service protocol.', 'Some enterprise APIs still use SOAP.'),
(29, 3, 'TTL', 'A value that controls how long data remains valid or cached.', 'Time before data expires.', 'DNS records often include a TTL.'),
(30, 3, 'ICMP', 'A network protocol used for control messages and diagnostics.', 'Network diagnostic protocol.', 'Ping commonly uses ICMP messages.'),
(31, 4, 'Esc', 'Short for Escape, a keyboard key often used to cancel or exit an action.', 'Cancel key.', 'Press Esc to close a dialog box.'),
(32, 4, 'Keyboard', 'An input device used to type text and commands.', 'Typing device.', 'Use the keyboard to enter an answer.'),
(33, 4, 'Mouse', 'A pointing device used to move a cursor and select items.', 'Cursor controller.', 'Click the submit button with a mouse.'),
(34, 4, 'Monitor', 'An output device that displays visual information.', 'Computer screen.', 'The quiz appears on the monitor.'),
(35, 4, 'Printer', 'An output device that produces text or images on paper.', 'Paper output device.', 'A printer can print a study sheet.'),
(36, 4, 'CPU', 'The main processor that executes instructions in a computer.', 'Computer brain.', 'The CPU runs program instructions.'),
(37, 4, 'RAM', 'Temporary working memory used while programs are running.', 'Short-term memory.', 'More RAM helps multiple apps run at once.'),
(38, 4, 'USB', 'A common standard for connecting devices and transferring data or power.', 'Common device connector.', 'A flash drive can connect through USB.'),
(39, 4, 'Webcam', 'A camera connected to or built into a computer for video input.', 'Computer camera.', 'A webcam can be used in online meetings.'),
(40, 4, 'Hard Drive', 'A storage device used to save files and programs.', 'Long-term storage.', 'A hard drive stores documents and apps.'),
(41, 5, 'iPod', 'A portable media player first released by Apple in 2001.', 'Apple music player.', 'The first iPod was released in 2001.'),
(42, 5, 'GPU', 'A processor specialized for graphics and parallel workloads.', 'Graphics processor.', 'A GPU renders game graphics.'),
(43, 5, 'Motherboard', 'The main circuit board that connects core computer components.', 'Main board.', 'The CPU and RAM are installed on the motherboard.'),
(44, 5, 'SSD', 'A storage device that uses flash memory instead of spinning disks.', 'Fast storage drive.', 'An SSD can improve boot time.'),
(45, 5, 'HDMI', 'A digital interface used to transmit audio and video.', 'Display cable standard.', 'A laptop can connect to a monitor through HDMI.'),
(46, 5, 'Ethernet', 'A wired networking technology commonly used in local area networks.', 'Wired network connection.', 'A desktop may connect to a router with Ethernet.'),
(47, 5, 'Processor Core', 'An individual processing unit inside a CPU.', 'One CPU working unit.', 'A quad-core CPU has four processor cores.'),
(48, 5, 'Heat Sink', 'A component that helps move heat away from another component.', 'Cooling block.', 'A CPU often uses a heat sink.'),
(49, 5, 'SATA', 'An interface used to connect storage devices such as hard drives and SSDs.', 'Storage connection interface.', 'A SATA cable can connect a hard drive.'),
(50, 5, 'Expansion Card', 'A circuit board added to a computer to provide extra features.', 'Add-on card.', 'A sound card can be an expansion card.'),
(51, 6, 'DMA', 'Direct Memory Access, a feature that lets hardware transfer data without constant CPU involvement.', 'Hardware data transfer path.', 'DMA can move data between memory and a device efficiently.'),
(52, 6, 'ALU', 'The arithmetic logic unit, the part of a CPU that performs arithmetic and logic operations.', 'CPU math logic unit.', 'The ALU can add numbers and compare values.'),
(53, 6, 'CMOS', 'Low-power semiconductor technology associated with motherboard settings memory in PCs.', 'Motherboard settings memory term.', 'Some firmware settings are associated with CMOS memory.'),
(54, 6, 'ECC', 'Error-correcting code memory technology that can detect and correct certain data errors.', 'Self-checking memory.', 'Servers often use ECC memory.'),
(55, 6, 'FPGA', 'A field-programmable gate array that can be configured after manufacturing.', 'Reconfigurable chip.', 'An FPGA can be programmed for a specialized task.'),
(56, 6, 'RISC', 'A processor design approach based on a reduced instruction set.', 'Simpler instruction CPU design.', 'ARM is commonly associated with RISC-style design.'),
(57, 6, 'CISC', 'A processor design approach based on a complex instruction set.', 'Complex instruction CPU design.', 'x86 is commonly associated with CISC-style design.'),
(58, 6, 'Northbridge', 'A chipset component that historically connected the CPU to high-speed components.', 'Older fast chipset bridge.', 'Older PCs used a northbridge for CPU-memory communication.'),
(59, 6, 'NVMe', 'A storage protocol designed for fast SSDs over PCI Express.', 'Fast SSD protocol.', 'Many M.2 SSDs use NVMe.'),
(60, 6, 'IOPS', 'Input/output operations per second, a storage performance measurement.', 'Storage operations per second.', 'SSDs often advertise high IOPS.'),
(61, 7, 'Toolbar', 'A row or group of buttons for common commands in an application.', 'Button bar.', 'The toolbar may contain Save and Undo buttons.'),
(62, 7, 'App', 'A software application designed to perform tasks for users.', 'User program.', 'A quiz app helps students practice terms.'),
(63, 7, 'Program', 'A set of instructions that a computer can run.', 'Runnable instructions.', 'A browser is a program.'),
(64, 7, 'Folder', 'A container used to organize files.', 'File container.', 'A project folder can contain source files.'),
(65, 7, 'File Extension', 'The suffix at the end of a filename that indicates file type.', 'Filename ending.', 'The .ts extension often means a TypeScript file.'),
(66, 7, 'Desktop', 'The main workspace shown by an operating system after login.', 'Main computer workspace.', 'Shortcuts may appear on the desktop.'),
(67, 7, 'Window', 'A rectangular screen area that displays an app or document.', 'App box on screen.', 'The quiz opens in a browser window.'),
(68, 7, 'Text Editor', 'A program used to create and edit plain text files.', 'Plain text editing app.', 'Developers often write code in a text editor.'),
(69, 7, 'Backup', 'A copy of data kept so it can be restored later.', 'Safety copy.', 'Make a backup before changing important files.'),
(70, 7, 'Document', 'An electronic file containing text, media, or other content.', 'Electronic paper.', 'A report can be saved as a document.'),
(71, 8, 'File', 'A named item of data stored on a computer.', 'Saved digital item.', 'A PDF can be stored as a file.'),
(72, 8, 'API', 'A defined way for software components to communicate.', 'Software contract.', 'The frontend calls an API to get quiz data.'),
(73, 8, 'Function', 'A reusable block of code that performs a specific task.', 'Reusable code action.', 'A function can calculate a score.'),
(74, 8, 'Loop', 'A programming structure that repeats instructions.', 'Repeat block.', 'A loop can process all questions.'),
(75, 8, 'Query', 'A request for information from a database or search system.', 'Ask a system for data.', 'A SQL query can select lessons.'),
(76, 8, 'Runtime', 'The period when a program is executing.', 'When software is running.', 'A runtime error appears while the app runs.'),
(77, 8, 'GUI', 'A graphical user interface that uses visual elements for interaction.', 'Visual interface.', 'Buttons and windows are part of a GUI.'),
(78, 8, 'Patch', 'A software update that fixes bugs or improves behavior.', 'Fix update.', 'A patch can fix a login bug.'),
(79, 8, 'Permissions', 'Rules that define what a user or program may access or change.', 'Access rules.', 'Admin permissions may be required.'),
(80, 8, 'Version Control', 'A system for tracking changes to files over time.', 'Code history management.', 'Git is used for version control.'),
(81, 9, 'Interpreter', 'A program that parses and executes script code.', 'Script runner.', 'A JavaScript engine can interpret code.'),
(82, 9, 'Compiler', 'A program that translates source code into another form, often machine code.', 'Code translator.', 'A compiler can turn C++ into an executable.'),
(83, 9, 'Kernel', 'The core part of an operating system that manages resources.', 'OS core.', 'The kernel manages memory and processes.'),
(84, 9, 'Deadlock', 'A state where processes wait on each other and cannot continue.', 'Processes stuck waiting.', 'A deadlock can occur when two processes each hold a needed resource.'),
(85, 9, 'Race Condition', 'A bug where behavior depends on unpredictable timing between operations.', 'Timing bug.', 'A race condition can appear when two requests update the same value.'),
(86, 9, 'Garbage Collection', 'Automatic memory management that frees objects no longer in use.', 'Automatic memory cleanup.', 'JavaScript uses garbage collection.'),
(87, 9, 'Bytecode', 'Intermediate code that can be executed by a virtual machine or runtime.', 'Middle form code.', 'Java source can compile into bytecode.'),
(88, 9, 'System Call', 'A request made by a program to the operating system kernel.', 'Program asks OS service.', 'Reading a file may require a system call.'),
(89, 9, 'SQL Injection', 'A security vulnerability where malicious SQL is inserted through input.', 'Database input attack.', 'Parameterized queries help prevent SQL injection.'),
(90, 9, 'Design Pattern', 'A reusable solution template for a common software design problem.', 'Reusable design solution.', 'MVC is often discussed as a design pattern.');
